return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progress = (t % duration) / duration;

    var centerX = W / 2;
    var centerY = H / 2 - 15;
    var radius = 70;

    // Slices count
    var totalSlices = 4;
    var targetShaded = 3;

    // Calculate current shaded slices based on progress
    var currentShaded = 0;
    if (progress >= 0.15 && progress < 0.35) currentShaded = 1;
    else if (progress >= 0.35 && progress < 0.55) currentShaded = 2;
    else if (progress >= 0.55) currentShaded = 3;

    // Draw slices
    for (var i = 0; i < totalSlices; i++) {
      var startAngle = i * (Math.PI * 2 / totalSlices) - Math.PI / 2;
      var endAngle = (i + 1) * (Math.PI * 2 / totalSlices) - Math.PI / 2;

      ctx.beginPath();
      ctx.moveTo(centerX, centerY);
      ctx.arc(centerX, centerY, radius, startAngle, endAngle);
      ctx.closePath();

      if (i < currentShaded) {
        ctx.fillStyle = '#3B82F6'; // Shaded blue
        ctx.fill();
        ctx.strokeStyle = '#60A5FA';
      } else {
        ctx.fillStyle = '#1F2937'; // Unshaded dark gray
        ctx.fill();
        ctx.strokeStyle = '#374151';
      }
      ctx.lineWidth = 2.5;
      ctx.stroke();
    }

    // Label text
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 20px -apple-system, sans-serif';

    if (currentShaded === 0) {
      ctx.fillText('0 / 4 Slices Shaded', centerX, H - 40);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('Starting with an empty whole divided into 4 parts', centerX, H - 18);
    } else if (currentShaded === 1) {
      ctx.fillText('1 / 4 Shaded', centerX, H - 40);
      ctx.fillStyle = '#60A5FA';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('One equal part of the whole (Numerator = 1)', centerX, H - 18);
    } else if (currentShaded === 2) {
      ctx.fillText('2 / 4 Shaded (or 1/2)', centerX, H - 40);
      ctx.fillStyle = '#60A5FA';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('Two equal parts of the whole (Numerator = 2)', centerX, H - 18);
    } else {
      ctx.fillText('3 / 4 Shaded', centerX, H - 40);
      ctx.fillStyle = '#34D399';
      ctx.font = 'bold 14px -apple-system, sans-serif';
      ctx.fillText('Proper Fraction: 3 < 4 (Value is less than 1 whole)', centerX, H - 18);
    }
  }
};
